import "./switch.css";

import { Switch } from "radix-ui";
import { cn } from "tailwind-variants";

import { switchVariants } from "./switch.variants";

export type SwitchProps = React.ComponentProps<typeof Switch.Root>;

export const SwitchRoot = ({ className, ...props }: SwitchProps) => {
  const { root, thumb } = switchVariants();

  return (
    <Switch.Root className={cn(root(), className)} {...props}>
      <Switch.Thumb className={thumb()} />
    </Switch.Root>
  );
};

import { tv, type VariantProps } from "tailwind-variants";

export const switchVariants = tv({
  slots: {
    root: "switch",
    thumb: "switch__thumb",
  },
});

export type SwitchVariants = VariantProps<typeof switchVariants>;

.switch {
  @apply inline-flex h-5 w-9 shrink-0 cursor-pointer items-center rounded-full border-2 border-transparent shadow-sm transition-colors;

  &:focus-visible {
    @apply outline-ring outline-2 outline-offset-2;
  }

  &:disabled {
    @apply cursor-not-allowed opacity-50;
  }

  &[data-state="unchecked"] {
    @apply bg-input;
  }

  &[data-state="checked"] {
    @apply bg-primary;
  }
}

.switch__thumb {
  @apply bg-background pointer-events-none block size-4 rounded-full shadow-lg ring-0 transition-transform;

  &[data-state="unchecked"] {
    @apply translate-x-0;
  }

  &[data-state="checked"] {
    @apply translate-x-4;
  }
}

import { SwitchRoot } from "./switch";

export const Switch = {
  Root: SwitchRoot,
};

export { SwitchRoot };

export { type SwitchVariants, switchVariants } from "./switch.variants";
